const games = $json.sports_results?.games || [];

// take latest match
const match = games[0];

return [{
  json: {
    team1: match.teams[0].name,
    team2: match.teams[1].name,
    score1: match.teams[0].score,
    score2: match.teams[1].score,
    result: match.status,
    tournament: match.tournament
  }
}];
